class Solution:
    def nthUglyNumber(self, n: int) -> int:
        if n == 1:
            return 1
        ugly = [1]
        i2 = i3 = i5 = 0
        while len(ugly) < n:
            next2 = 2 * ugly[i2]
            next3 = 3 * ugly[i3]
            next5 = 5 * ugly[i5]
            new_num = min(next2, next3, next5)
            ugly.append(new_num)
            if new_num == next2:
                i2 += 1
            if new_num == next3:
                i3 += 1
            if new_num == next5:
                i5 += 1
        return ugly[-1]

